# An implementation of the recursive fork fibonacci parallelism test.
#
# Canonical (TooManyCooks) implementation:
# ../../cpp/TooManyCooks/fib.cpp
#
# Fork fib(n-1) as a Weave task (spawn) to run in parallel with the current
# task, then continue the other leg (fib(n-2)) serially. This measures Weave's
# task spawn/sync throughput.
#
# The explicit {.gcsafe.} is required on Nim 2.x: gcsafety is not inferred for
# recursive procs, and the task wrapper generated by Weave's spawn demands it.

import std/[monotimes, os, strutils, times]
import weave
import benchutil

const iterCount = 1

proc fib(n: uint64): uint64 {.gcsafe.} =
  if n < 2:
    return n
  let x = spawn fib(n - 1)
  let y = fib(n - 2)
  result = sync(x) + y

proc main() =
  if paramCount() < 1:
    echo "Usage: fib <n-th fibonacci number requested>"
    return
  var n: uint64
  try:
    n = parseBiggestUInt(paramStr(1)).uint64
  except ValueError:
    echo "Usage: fib <n-th fibonacci number requested>"
    return
  let threadCount = threadCountArg(2)
  echo "threads: ", threadCount

  setWeaveThreads(threadCount)
  init(Weave)

  discard fib(30) # warmup

  let start = getMonoTime()
  var res: uint64
  for _ in 0 ..< iterCount:
    res = fib(n)
  let durUs = (getMonoTime() - start).inMicroseconds
  exit(Weave)
  echo "output: ", res

  echo "runs:"
  echo "  - iteration_count: ", iterCount
  echo "    duration: ", durUs, " us"
  echo "    max_rss: ", peakMemoryUsageKiB(), " KiB"

when isMainModule:
  main()
